var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"으아… 빈틈이 없어. 별로 상대는 지친 것 같지도 않아.","JPN":"うう…隙がない。会長は全然疲れていないし。","ENG":"Ugh, I can't find an opening. She doesn't look exhausted, either.","TWN":"可惡…沒有破綻！她好像都不會累？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REBBIT_SUMMON_NULL_NULL","text":{"KOREA":"픽… 픽…","JPN":"ピィ……ピィ……","ENG":"Piiik... Piiik...","TWN":"嗶…嗶…"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"기량은 훌륭하지만, 동작이 너무 크군요.","JPN":"技量はお見事ですが、動作が大袈裟すぎますね。","ENG":"You're good, but your moves are unnecessarily big.","TWN":"技巧不錯，可惜動作太大。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"공격 또한 너무 단조로워서 검을 한 번 맞대는 것만으로 흐름을 알 수 있어요.","JPN":"攻撃も単調すぎて、剣を交わすだけで動きの流れが読み取れます。","ENG":"Too predictable, too. I've figured out your style after our first clash of swords.","TWN":"攻擊的方式也太呆板，一下就可以摸清你的套路。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REBBIT_SUMMON_NULL_NULL","text":{"KOREA":"피이……","JPN":"ピィ……","ENG":"Piii...","TWN":"嗶……"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REBBIT_SUMMON_NULL_NULL","text":{"KOREA":"피픽? 픽! 픽!","JPN":"ピィ？　ピー！　ピー！","ENG":"Piiipik? Piik! Piik!","TWN":"嗶嗶？嗶！嗶！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"음? 하늘에 UFO가 있다고요?","JPN":"え？　空にUFOがいるですって？","ENG":"Huh? There's a UFO in the sky?","TWN":"什麼？天上有UFO？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"REBBIT_SUMMON_NULL_NULL","text":{"KOREA":"피이익…","JPN":"ピィ……！","ENG":"Piiiik...","TWN":"嗶嗶…"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"조금 당혹스럽군요.","JPN":"これは少々参りましたね。","ENG":"I'm a bit disconcerted.","TWN":"我應該沒眼花吧？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"실전에서 정말로 이런 속임수를 쓰는 경우를 보게 될 줄은 몰랐는데 말이죠.","JPN":"実戦でこんなトリックを使うケースを目にするとは思っていませんでした。","ENG":"I've never met anyone else using such a trick in a real fight.","TWN":"沒想到會在實戰中見識到這種小孩子的把戲。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"헥 헥… 더는 못 휘두르겠어.","JPN":"はぁはぁ……もう無理だよ。","ENG":"Huff, huff... I can't swing my gun anymore.","TWN":"呼呼…我沒力氣了啦！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"음…… 약점을 파악 당한 본관의 완벽한 패배로군.","JPN":"むむ……弱点を突かれた本官の完全な敗北だな。","ENG":"Mm... This is my complete defeat. She's seen through my weakness.","TWN":"嗯…本官的弱點完全被對方看穿，本官承認戰敗！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"갑작스럽게 과자 공세를 펼칠 줄은 예상하지 못 했다.","JPN":"急にお菓子攻撃をされるとは予想もできなかった。","ENG":"I can't believe she used cookies to distract me so all of a sudden.","TWN":"沒想到竟然會突然使出餅乾攻勢。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"……냠-","JPN":"……(もぐもぐ)。","ENG":"*Yum*","TWN":"阿姆阿姆…"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"역시…… 우리가 힘을 합쳐도 학생회장님에겐 안되는 건가.","JPN":"やっぱり……私たちが力を合わせても生徒会長には勝てないね。","ENG":"I knew it. Even among the three of us, we're no match for the Student President.","TWN":"果然……三個臭皮匠加起來，還是無法勝過一個學生會長嗎？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아쉽지만, 패배를 인정할게요.","JPN":"残念ですが、私たちの敗北を認めます。","ENG":"This is disappointing, but we accept our defeat.","TWN":"雖然很遺憾，我承認是我們輸了。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"좋은 승부였습니다.","JPN":"いい勝負でしたね。","ENG":"That was a good match.","TWN":"是場精彩的對決。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};